<template><div class="health-guard-config-grid"><label v-for="field in fields" :key="field.key" class="health-guard-field"><span>{{ t(field.label) }}</span><input :data-test="`health-guard-field-${field.key}`" type="number" :min="field.min" :max="field.max" :step="field.step" class="input" :value="values[field.key]" @input="emitField(field.key,$event)" /></label><div class="health-guard-field health-guard-field-wide"><span>{{ t('admin.upstreamProviders.healthGuardIgnoredAccounts') }}</span><div class="health-guard-ignored-summary" :class="{'is-invalid':ignoredInputInvalid}"><div><strong>{{ ignoredSummaryText }}</strong><small>{{ t('admin.upstreamProviders.healthGuardIgnoredAccountsHint') }}</small></div><button class="btn btn-secondary btn-sm" data-test="health-guard-ignored-manage" @click="$emit('manage-ignored')">{{ t('admin.upstreamProviders.healthGuardIgnoredManage') }}</button></div><div v-if="ignoredInputInvalid">{{ t('admin.upstreamProviders.invalidHealthGuardIgnoredAccounts') }}</div></div></div></template>
<script setup lang="ts">import{useI18n}from'vue-i18n';type K='interval_seconds'|'max_accounts_per_run'|'concurrency'|'timeout_per_account_seconds'|'failure_threshold'|'slow_threshold'|'recovery_threshold'|'healthy_latency_ms';defineProps<{values:Record<K,number>;ignoredSummaryText:string;ignoredInputInvalid:boolean}>();const emit=defineEmits<{'update:field':[K,number];'manage-ignored':[]}>();const{t}=useI18n();const fields:Array<{key:K;label:string;min:number;max?:number;step:number}>=[{key:'interval_seconds',label:'admin.upstreamProviders.healthGuardIntervalSeconds',min:60,step:60},{key:'max_accounts_per_run',label:'admin.upstreamProviders.healthGuardMaxAccounts',min:1,max:1000,step:1},{key:'concurrency',label:'admin.upstreamProviders.healthGuardConcurrency',min:1,max:8,step:1},{key:'timeout_per_account_seconds',label:'admin.upstreamProviders.healthGuardTimeout',min:5,max:300,step:5},{key:'failure_threshold',label:'admin.upstreamProviders.healthGuardFailureThreshold',min:1,step:1},{key:'slow_threshold',label:'admin.upstreamProviders.healthGuardSlowThreshold',min:1,step:1},{key:'recovery_threshold',label:'admin.upstreamProviders.healthGuardRecoveryThreshold',min:1,step:1},{key:'healthy_latency_ms',label:'admin.upstreamProviders.healthGuardHealthyLatency',min:1,step:500}];function emitField(k:K,e:Event){emit('update:field',k,Number((e.target as HTMLInputElement).value))}</script>
<style scoped>.health-guard-config-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}.health-guard-field{display:grid;gap:6px}.health-guard-field-wide{grid-column:1/-1}.health-guard-ignored-summary{display:flex;justify-content:space-between;gap:12px;border:1px solid #e5e7eb;border-radius:10px;padding:10px 12px}.health-guard-ignored-summary>div{display:grid}.is-invalid{border-color:#fecaca;background:#fef2f2}@media(max-width:768px){.health-guard-config-grid{grid-template-columns:1fr}.health-guard-ignored-summary{flex-direction:column}}</style>
